package main.rice;

import java.util.Arrays;

/**
 * This class implements a relatively simple algorithm for computing (and printing) the
 * prime factors of a number.  At initialization, a list of primes is computed. Given a
 * number, this list is used to efficiently compute the prime factors of that number.
 */
public class PrimeFactorizer {

    private final int maxNum;
    private final int[] primes;

    /**
     * Initialize the factorizer to handle numbers up to maxNumToFactorize.
     * Pre-compute primes up to this maximum for efficiency.
     *
     * @param maxNumToFactorize the maximum number that this factorizer can handle
     */
    public PrimeFactorizer(int maxNumToFactorize) {
        this.maxNum = maxNumToFactorize;
        if (maxNumToFactorize < 2) {
            this.primes = new int[0];
            return;
        }

        // Sieve of Eratosthenes to find all primes up to maxNumToFactorize
        boolean[] isPrime = new boolean[maxNumToFactorize + 1];
        Arrays.fill(isPrime, true);
        isPrime[0] = false;
        isPrime[1] = false;

        for (int p = 2; (long) p * p <= maxNumToFactorize; p++) {
            if (isPrime[p]) {
                for (int i = p * p; i <= maxNumToFactorize; i += p) {
                    isPrime[i] = false;
                }
            }
        }

        // Count the number of primes found
        int count = 0;
        for (int i = 2; i <= maxNumToFactorize; i++) {
            if (isPrime[i]) {
                count++;
            }
        }

        // Store the primes in an array
        this.primes = new int[count];
        int index = 0;
        for (int i = 2; i <= maxNumToFactorize; i++) {
            if (isPrime[i]) {
                this.primes[index++] = i;
            }
        }
    }

    /**
     * Return an array containing the prime factors of numToFactorize in ascending order.
     * Include repeated factors (e.g., 12 = [2, 2, 3]).
     *
     * @param numToFactorize the number to factorize
     * @return an array of prime factors, or null if the number is invalid or exceeds maxNum
     */
    public int[] computePrimeFactorization(int numToFactorize) {
        // Edge cases: Negative numbers, 0, 1, and numbers exceeding maxNumToFactorize
        if (numToFactorize <= 1 || numToFactorize > this.maxNum) {
            return null;
        }

        // A 32-bit signed integer can have at most 31 prime factors (all 2s)
        int[] factors = new int[32];
        int count = 0;
        int temp = numToFactorize;

        // Trial division using pre-computed primes
        for (int p : this.primes) {
            // If p*p > temp, then temp must be prime (or 1)
            if ((long) p * p > temp) {
                break;
            }
            while (temp % p == 0) {
                factors[count++] = p;
                temp /= p;
            }
        }

        // If there's a remaining factor greater than 1, it must be prime
        if (temp > 1) {
            factors[count++] = temp;
        }

        // Return only the filled portion of the factors array
        return Arrays.copyOf(factors, count);
    }
}

