package test.rice;

import main.rice.PrimeFactorizer;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertArrayEquals;
import static org.junit.jupiter.api.Assertions.assertNull;

public class PrimeFactorizerAgentTest {

    private static final PrimeFactorizer factorizer = new PrimeFactorizer(1000);
    private static final PrimeFactorizer largeFactorizer = new PrimeFactorizer(50000000);

    @Test
    void testFactorize1() {
        assertNull(factorizer.computePrimeFactorization(1));
    }

    @Test
    void testFactorize2() {
        assertArrayEquals(new int[]{2}, factorizer.computePrimeFactorization(2));
    }

    @Test
    void testFactorize4() {
        assertArrayEquals(new int[]{2, 2}, factorizer.computePrimeFactorization(4));
    }

    @Test
    void testFactorize12() {
        assertArrayEquals(new int[]{2, 2, 3}, factorizer.computePrimeFactorization(12));
    }

    @Test
    void testFactorizePrime() {
        assertArrayEquals(new int[]{997}, factorizer.computePrimeFactorization(997));
    }

    @Test
    void testFactorizeMax() {
        assertArrayEquals(new int[]{2, 2, 2, 5, 5, 5}, factorizer.computePrimeFactorization(1000));
    }

    @Test
    void testFactorizeLargerThanMax() {
        assertNull(factorizer.computePrimeFactorization(1001));
    }

    @Test
    void testLargeFactorizerPrime() {
        // 49,999,991 is prime
        assertArrayEquals(new int[]{49999991}, largeFactorizer.computePrimeFactorization(49999991));
    }

    @Test
    void testLargeFactorizerComposite() {
        // 49,999,990 = 2 * 5 * 4999999
        // Is 4,999,999 prime? 
        // 4999999 / 7 = 714285.57
        // 4999999 is not easily factorable in head.
        // Let's use something simpler.
        // 50,000,000 = 2^7 * 5^8
        int[] expected = new int[]{2, 2, 2, 2, 2, 2, 2, 5, 5, 5, 5, 5, 5, 5, 5};
        assertArrayEquals(expected, largeFactorizer.computePrimeFactorization(50000000));
    }
}
